Javascript.validate:
	//cannot be in past : working day only
	
	var checkDate = Services.getValue(StatementsExhDate.dataBinding); 
	var err = null;
	
	if( false == isFutureDate(checkDate))
	{ 	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg");
	}
	else if( isNonWorkingDate(checkDate))
    {   err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg"); 
    }
	
	return err;
